r(--omg-radius-full);min-width:18px;text-align:center}.omg-ds__category-scope{font-size:9px;font-weight:var(--omg-font-weight-semibold);text-transform:uppercase;letter-spacing:0.04em;padding:1px 5px;border-radius:var(--omg-radius-sm)}.omg-ds__category-scope--shared{color:var(--omg-info);background:hsla(205,70%,52%,0.12)}.omg-ds__category-scope--character{color:var(--omg-success);background:hsla(152,55%,42%,0.12)}.omg-ds__main{flex:1;display:flex;flex-direction:column;gap:var(--omg-space-md);min-width:0}.omg-ds__entries-header{display:flex;align-items:center;justify-content:space-between;flex-wrap:wrap;gap:var(--omg-space-sm)}.omg-ds__entries-title{font-size:var(--omg-font-md);font-weight:var(--omg-font-weight-semibold);color:var(--omg-text-primary);margin:0}.omg-ds__entries-scope{font-weight:var(--omg-font-weight-normal);color:var(--omg-text-tertiary);font-size:var(--omg-font-sm)}.omg-ds__entries-actions{display:flex;gap:var(--omg-space-xs)}.omg-ds__entries-list{display:flex;flex-direction:column;gap:2px;flex:1;overflow-y:auto}.omg-ds__entry-row{display:flex;align-items:center;gap:var(--omg-space-sm);padding:var(--omg-space-sm) var(--omg-space-md);background:var(--omg-bg-secondary);border-radius:var(--omg-radius-md);cursor:pointer;transition:all var(--omg-transition-fast);border:1px solid transparent}.omg-ds__entry-row:hover{background:var(--omg-bg-tertiary)}.omg-ds__entry-row--active{border-color:var(--omg-accent);background:var(--omg-accent-subtle)}.omg-ds__entry-icon{width:20px;text-align:center;color:var(--omg-text-tertiary);font-size:var(--omg-font-sm)}.omg-ds__entry-info{flex:1;display:flex;flex-direction:column;min-width:0}.omg-ds__entry-name{font-size:var(--omg-font-sm);font-weight:var(--omg-font-weight-medium);color:var(--omg-text-primary)}.omg-ds__entry-key{font-size:var(--omg-font-xs);color:var(--omg-text-tertiary);font-family:var(--omg-font-mono)}.omg-ds__entry-type{font-size:var(--omg-font-xs);color:var(--omg-text-tertiary);padding:2px 8px;background:var(--omg-bg-primary);border-radius:var(--omg-radius-sm);white-space:nowrap}.omg-ds__editor{border-top:1px solid var(--omg-border);padding-top:var(--omg-space-lg);display:flex;flex-direction:column;gap:var(--omg-space-md)}.omg-ds__editor-header{display:flex;align-items:center;justify-content:space-between}.omg-ds__editor-title{font-size:var(--omg-font-md);font-weight:var(--omg-font-weight-semibold);color:var(--omg-text-primary);margin:0}.omg-ds__editor-body{display:flex;flex-direction:column;gap:var(--omg-space-md)}.omg-ds__editor-row{display:grid;grid-template-columns:1fr 1fr;gap:var(--omg-space-md)}.omg-ds__editor-field{display:flex;flex-direction:column;gap:4px}.omg-ds__editor-label{font-size:var(--omg-font-xs);color:var(--omg-text-secondary);font-weight:var(--omg-font-weight-medium)}.omg-ds__textarea{width:100%;padding:8px 12px;font-size:var(--omg-font-sm);font-family:var(--omg-font-family);color:var(--omg-text-primary);background:var(--omg-bg-secondary);border:1px solid var(--omg-border);border-radius:var(--omg-radius-md);outline:none;resize:vertical;transition:border-color var(--omg-transition-fast)}.omg-ds__textarea:focus{border-color:var(--omg-border-focus);box-shadow:0 0 0 3px var(--omg-accent-subtle)}.omg-ds__textarea--code{font-family:var(--omg-font-mono);font-size:var(--omg-font-xs)}.omg-ds__zod-preview{display:block;padding:8px 12px;font-family:var(--omg-font-mono);font-size:var(--omg-font-xs);color:var(--omg-accent);background:var(--omg-bg-secondary);border-radius:var(--omg-radius-md);border:1px solid var(--omg-border)}.omg-ds__editor-actions{display:flex;justify-content:flex-end;padding-top:var(--omg-space-sm)}.omg-ds__category-form{display:flex;flex-direction:column;gap:var(--omg-space-md)}.omg-slide-enter-active,.omg-slide-leave-active{transition:all var(--omg-transition-normal)}.omg-slide-enter-from,.omg-slide-leave-to{opacity:0;transform:translateY(8px)}@media (max-width:768px){.omg-ds__content{flex-direction:column}.omg-ds__categories{width:100%}.omg-ds__category-list{display:flex;flex-wrap:wrap;gap:var(--omg-space-xs)}.omg-ds__category-item{width:auto}.omg-ds__editor-row{grid-template-columns:1fr}}.omg-ds__style-row{display:flex;align-items:center;gap:var(--omg-space-xs)}.omg-ds__select{flex:1;padding:6px 10px;font-size:var(--omg-font-sm);font-family:var(--omg-font-family);color:var(--omg-text-primary);background:var(--omg-bg-primary);border:1px solid var(--omg-border);border-radius:var(--omg-radius-md);outline:none}.omg-ds__select:focus{border-color:var(--omg-accent)}.omg-ds__link-btn{display:flex;align-items:center;justify-content:center;width:28px;height:28px;border:1px solid var(--omg-border);background:var(--omg-bg-secondary);color:var(--omg-text-tertiary);cursor:pointer;border-radius:var(--omg-radius-md);font-size:var(--omg-font-xs);transition:all var(--omg-transition-fast);flex-shrink:0}.omg-ds__link-btn:hover{color:var(--omg-accent);border-color:var(--omg-accent);background:var(--omg-accent-subtle)}
